import{_ as e,c as i,o as a,a3 as t}from"./chunks/framework.6s30bTua.js";const g=JSON.parse('{"title":"Object-Oriented Programming (OOP)","description":"Object-oriented programming is a programming paradigm based on the concept of \\"objects\\"","frontmatter":{"title":"Object-Oriented Programming (OOP)","description":"Object-oriented programming is a programming paradigm based on the concept of \\"objects\\""},"headers":[],"relativePath":"Concepts/Programming_Paradigms/Object-Oriented_Programming.md","filePath":"Concepts/Programming_Paradigms/Object-Oriented_Programming.md","lastUpdated":1668244097000}'),o={name:"Concepts/Programming_Paradigms/Object-Oriented_Programming.md"},n=t('<h1 id="object-oriented-programming-oop" tabindex="-1">Object-Oriented Programming (OOP) <a class="header-anchor" href="#object-oriented-programming-oop" aria-label="Permalink to &quot;Object-Oriented Programming (OOP)&quot;">​</a></h1><p>Object-oriented programming is a programming paradigm based on the concept of &quot;<a href="#objects">objects</a>&quot;, which can contain data and code: data in the form of fields, and code, in the form of procedures</p><p>Other programming paradigms:</p><ul><li>Logic Programming Language: Prolog</li><li>Functional Programming Language: Haskell</li></ul><p>To solve a problem:</p><ul><li>Analysis: Understand the problem</li><li>Design: Plan your solution</li><li>Programming: Build the solution</li></ul><h2 id="objects" tabindex="-1">Objects <a class="header-anchor" href="#objects" aria-label="Permalink to &quot;Objects&quot;">​</a></h2><p>Objects are instances of a <a href="#classes">class</a>. Objects are instantiated from Classes</p><ul><li>Attributes, properties, characteristics, state, fields, variables</li></ul><p>All objects have:</p><ul><li>Identity: Olivia&#39;s coffee mug</li><li>Attributes: colour, size, fullness</li><li>behaviours: <code>fill()</code>, <code>empty()</code>, <code>clean()</code></li></ul><p>Objects are often referred to as Nouns:</p><ul><li><p>Things, People, Places, Ideas, Concepts</p></li><li><p>Can &quot;The&quot; be placed in front of it: &quot;The mug&quot;, &quot;The bank account&quot;, &quot;The time&quot;</p></li><li><p>Not verbs: &quot;The texting&quot;, or &quot;The ringing&quot; as they describe the behaviour of an object, not the object itself</p></li></ul><h2 id="classes" tabindex="-1">Classes <a class="header-anchor" href="#classes" aria-label="Permalink to &quot;Classes&quot;">​</a></h2><p>Class is the code template for creating program <a href="#objects">Objects</a></p><ul><li>A Class can be used to create multiple objects</li><li>A Class itself is not an Object</li></ul><p>Class Components:</p><ul><li><p>Name (type): What is it? --&gt; RoundCookie, Car</p></li><li><p>Attributes (properties, data): What describes it? --&gt;weight, colour, icing</p></li><li><p>behaviour (operations): What can it do? --&gt; <code>decorate()</code>, <code>consume()</code></p></li></ul><h3 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h3><p>A program procedure that can return a value</p><ul><li><p>Methods are functions that are defined as part of a class</p></li><li><p>They can only access data known to it&#39;s object</p></li></ul><h2 id="fundamental-ideas" tabindex="-1">Fundamental Ideas <a class="header-anchor" href="#fundamental-ideas" aria-label="Permalink to &quot;Fundamental Ideas&quot;">​</a></h2><p>There are 4 fundamental ideas in OOP:</p><ol><li><a href="#abstraction">Abstraction</a></li><li><a href="#encapsulation">Encapsulation</a></li><li><a href="#inheritance">Inheritance</a></li><li><a href="#polymorphism">Polymorphism</a></li></ol><h3 id="abstraction" tabindex="-1">Abstraction <a class="header-anchor" href="#abstraction" aria-label="Permalink to &quot;Abstraction&quot;">​</a></h3><p>Abstraction refers to only showing essential details and keep everything else hidden</p><ul><li><p>Modelling the relevant attributes and interactions of entities as classes to define an abstract representation of a system</p></li><li><p>Interface and Implementation:</p><ul><li><p>The interface refers to the way sections of code can communicate with one another. This typically is done through methods that each class can access</p></li><li><p>The implementation of these methods, or how these methods are coded, should be hidden</p></li><li><p>If classes are entangled, then one change creates a ripple effect that causes many more changes</p></li><li><p>Creating an interface through which classes can interact ensures that each piece can be individually developed</p></li><li><p>Abstraction allows the program to be worked on incrementally and prevents it from becoming entangled and complex</p></li><li><p>Determine specific points of contact that can act as an interface between classes, and only worry about the implementation when coding it</p></li></ul></li><li><p>Focus on essential qualities of something rather than one specific example</p></li><li><p>Understanding the idea</p></li><li><p>Discard what&#39;s unimportant</p></li></ul><h3 id="encapsulation" tabindex="-1">Encapsulation <a class="header-anchor" href="#encapsulation" aria-label="Permalink to &quot;Encapsulation&quot;">​</a></h3><p>Encapsulation refers to bundling data with methods that can operate on that data within a class. Essentially, it is the idea of hiding data within a class, preventing anything outside that class from directly interacting with it</p><ul><li><p>Hiding the internal state and functionality of an object and only allowing access through a public set of functions.</p></li><li><p>Keeps the programmer in control of access to data</p></li><li><p>Prevents the program from ending up in any strange or unwanted states</p></li><li><p>Containing the elements of an object, not just keep them together, but also protect them</p></li><li><p>We bundle an object&#39;s attributes or data along with the methods that operate on that data within the same unit or the same class</p></li><li><p>Restricting access to some of the object&#39;s components</p></li><li><p>Black Box Testing: Closing off the inner workings of the cookie jar and only revealing specific inputs and outputs. You don&#39;t need to know how the &#39;request cookie&#39; method is implemented under the hood to use it</p></li><li><p>It&#39;s not about being secretive. It&#39;s about reducing dependencies between different parts of the application.</p></li><li><p>Changes in one place won&#39;t cause a domino effect and require multiple changes elsewhere</p></li></ul><h3 id="inheritance" tabindex="-1">Inheritance <a class="header-anchor" href="#inheritance" aria-label="Permalink to &quot;Inheritance&quot;">​</a></h3><p>Inheritance is the principle that allows classes to derive from other classes</p><ul><li><p>Ability to create new abstractions based on existing abstractions.</p></li><li><p>Base new object or class on an existing one</p></li><li><p>Inherit the existing attributes and methods</p></li><li><p>Great form of code reuse</p></li><li><p>Superclass (Parent class) (Base class) --&gt; Inherited by --&gt; Subclass (Child class) (Derived class)</p></li><li><p>Multiple Inheritance: Inherit from multiple Base classes (can get confusing). C++, Python</p></li><li><p>Single Inheritance: Inherit from single Super class. Java, C#, Swift, Ruby</p></li></ul><h3 id="polymorphism" tabindex="-1">Polymorphism <a class="header-anchor" href="#polymorphism" aria-label="Permalink to &quot;Polymorphism&quot;">​</a></h3><p>Polymorphism describes methods that are able to take on many forms.</p><ul><li>Ability to implement inherited properties or methods in different ways across multiple abstractions.</li></ul><p>Polymorphism means having many forms</p><p>There are multiple form of polymorphism:</p><ul><li><p>Dynamic Polymorphism: Uses the same interface for methods on different types of objects</p><ul><li>Occurs during the runtime of the program</li><li>Describes when a method signature is in both a subclass and a superclass</li><li>The methods share the same name but have different implementation</li><li>Overriding methods</li><li>Inherit from the same abstract class with same methods</li><li>Inheritance, abstract classes, and interfaces are all possible implementations of polymorphism</li></ul></li><li><p>Static (Compile-Time) Polymorphism: Uses method overloading:</p><ul><li>Occurs during compile-time rather than during runtime</li><li>This refers to when multiple methods with the same name but different arguments are defined in the same class</li><li>This can done through method overloading. Despite the methods having the same name, their signatures are different due to their different arguments</li><li>Ways to differentiate methods of the same name: <ul><li>Different number of parameters</li><li>Different types of parameters</li><li>Different order of parameters</li></ul></li><li>Method overloading can cause trouble of you do not keep straight which parameters you need for which implementation. Calling the wrong method because not realizing different arguments types were passed</li><li>Implements multiple methods with the same name, but different parameters</li></ul></li></ul><h2 id="unified-modeling-language-uml" tabindex="-1">Unified Modeling Language (UML) <a class="header-anchor" href="#unified-modeling-language-uml" aria-label="Permalink to &quot;Unified Modeling Language (UML)&quot;">​</a></h2><p>Standardized notation for diagrams to visualize object-oriented systems.</p><p>Class Diagram:</p><ul><li>Name</li><li>Attributes</li><li>behaviours</li></ul><p>Structural diagrams:</p><ul><li>Class diagram</li><li>Component diagram</li><li>Deployment diagram</li><li>Object diagram</li><li>Package diagram</li><li>Profile diagram</li></ul><p>behavioural diagrams:</p><ul><li>Use case diagram</li><li>Activity diagram</li><li>State machine diagram</li><li>Sequence diagram</li><li>Communication diagram</li><li>Interaction overview diagram</li><li>Timing diagram</li></ul><p>UML Tools: Things to consider:</p><ul><li>Commercial or open source</li><li>Support platforms</li><li>Diagram drawing capabilities</li><li>Code generation capabilities</li></ul><p>5-Step approach:</p><ol><li><p>Gathering requirements to figure out what our application needs to do.</p></li><li><p>Describe the application. Build a narrative in plain, conversational language for how people will use it.</p></li><li><p>Identifying the most important objects, which is the starting point for identifying actual classes.</p></li><li><p>Describe the interactions between them, understanding each object&#39;s responsibilities, the behaviours they need to have, and when they interact with other objects.</p></li><li><p>And finally, create a class diagram, which serves as the main output from the five-step process.</p></li></ol>',51),l=[n];function s(r,c,p,h,d,m){return a(),i("div",null,l)}const f=e(o,[["render",s]]);export{g as __pageData,f as default};
